import React from 'react';
import { Box, Button, IconButton, Typography, useTheme } from "@mui/material";
import { tokens } from "../../Theme";
import Header from "../../components/Header/Header";
import StatBox from "../../components/StatBox";
import WorkOutlineIcon from '@mui/icons-material/WorkOutline';
import PointOfSaleIcon from "@mui/icons-material/PointOfSale";
import PersonAddIcon from "@mui/icons-material/PersonAdd";
import TrafficIcon from "@mui/icons-material/Traffic";
import FolderSpecialIcon from '@mui/icons-material/FolderSpecial';
import { useEffect, useState } from 'react';
import axios from 'axios';

const Dashboard = () => {
  const theme = useTheme();
  const colors = tokens(theme.palette.mode);
  const [username, setUsername] = useState('');
  const [projectCount, setProjectCount] = useState(0); // State for project coun
  const [userCount, setUserCount] = useState(0); // State for user count

  useEffect(() => {
    const employeeId = localStorage.getItem("cususerid");
    // Fetch the user's data
    axios.get(`http://localhost:8000/users/userdetail/${employeeId}/`)
      .then(response => {
        
        setUsername(response.data.name); // Changed from username to name
      })
      .catch(error => console.error('Error:', error));

      axios.get('http://localhost:8000/projects/projectcount/')
  .then(response => {
     
    setProjectCount(response.data.total_projects); // Access the total_projects property
  })
  .catch(error => console.error('Error:', error));

  axios.get('http://localhost:8000/users/usercount/')
  .then(response => {
     
    setUserCount(response.data.total_users); // Access the total_projects property
  })
  }, []);

  return (
    <Box m="20px">
      {/* HEADER */}
      <Box display="flex" justifyContent="space-between" alignItems="center">
        <Header title={`Heyy, ${username} 👋`} subtitle="Welcome to dashboard" />
      </Box>

      {/* GRID & CHARTS */}
      <Box
        display="grid"
        gridTemplateColumns="repeat(12, 1fr)"
        gridAutoRows="140px"
        gap="20px"
      >
        {/* ROW 1 */}

        <Box
          gridColumn="span 4"
          backgroundColor={colors.primary[400]}
          display="flex"
          alignItems="center"
          justifyContent="center"
        >
          <StatBox
            title={userCount.toString()} // Display the user count
            subtitle="Users Registered"
            progress="0.50"
            increase="+21%"
            icon={
              <PersonAddIcon
                sx={{ color: colors.greenAccent[600], fontSize: "26px" }}
              />
            }
          />
        </Box>
        <Box
          gridColumn="span 4"
          backgroundColor={colors.primary[400]}
          display="flex"
          alignItems="center"
          justifyContent="center"
        >
          <StatBox
            title={projectCount.toString()} // Display the project count
            subtitle="Total Projects"
            progress="0.75"
            increase="+14%"
            icon={
              <WorkOutlineIcon
                sx={{ color: colors.greenAccent[600], fontSize: "26px" }}
              />
            }
          />
        </Box>
        
        <Box
          gridColumn="span 4"
          backgroundColor={colors.primary[400]}
          display="flex"
          alignItems="center"
          justifyContent="center"
        >
          <StatBox
            title="32,441"
            subtitle="My Projects"
            progress="0.30"
            increase="+5%"
            icon={
              <FolderSpecialIcon
                sx={{ color: colors.greenAccent[600], fontSize: "26px" }}
              />
            }
          />
        </Box>
        <Box
          gridColumn="span 3"
          backgroundColor={colors.primary[400]}
          display="flex"
          alignItems="center"
          justifyContent="center"
        >
          <StatBox
            title="1,325,134"
            subtitle="Traffic Received"
            progress="0.80"
            increase="+43%"
            icon={
              <TrafficIcon
                sx={{ color: colors.greenAccent[600], fontSize: "26px" }}
              />
            }
          />
        </Box>
      </Box>
    </Box>
  );
}

export default Dashboard;
